function showLoadingSpinner(){const e=document.getElementById("loadingOverlay"),t=document.getElementById("spinnerText"),s=["Recherche des offres...","Analyse des prix...","Finalisation des résultats..."];let n=0;e.style.display="flex";const o=setInterval(()=>{if(n>0){const e=document.getElementById(`step${n}`);e.classList.remove("active"),e.classList.add("completed"),e.closest(".loading-step").querySelector(".step-label").classList.remove("active")}if(n++,n<=3){const e=document.getElementById(`step${n}`),o=e.closest(".loading-step").querySelector(".step-label");e.classList.add("active"),o.classList.add("active"),s[n-1]&&(t.textContent=s[n-1])}n>=3&&clearInterval(o)},1500)}function attachLoadingToForms(){document.querySelectorAll('form[action="/comparateur-des-prix"]').forEach(e=>{e.addEventListener("submit",function(){showLoadingSpinner()})})}document.addEventListener("DOMContentLoaded",attachLoadingToForms);